sql:
SELECT COUNT(roaster_id)
FROM roasters
WHERE status = 'active' AND website IS NOT NULL;

SELECT batch_number
FROM coffee_beans
WHERE STRFTIME('%Y', roast_date) = '2023' AND STRFTIME('%m', roast_date) = '06';

SELECT email 
FROM roasters 
WHERE roaster_id = 1;

SELECT roast_date 
FROM coffee_beans 
WHERE coffee_id = 1;

SELECT roaster_name, email 
FROM roasters 
WHERE status = 'active';
